+  requiredFields: [
+    "id",
+    "title",
+    "description",
+    "category",
+    "tags",
+    "author",
+    "version",
+    "content",
+    "created",
+  ] as const,
+
+  // Optional fields - MAY exist
+  optionalFields: [
+    "twitter",
+    "featured",
+    "difficulty",
+    "estimatedTokens",
+    "updatedAt",
+    "variables",
+    "whenToUse",
+    "tips",
+    "examples",
+    "changelog",
+  ] as const,
+
+  // Type constraints
+  types: {
+    id: "string",
+    title: "string",
+    description: "string",
+    category: "string",
+    tags: "array",
+    author: "string",
+    version: "string",
+    content: "string",
+    created: "string",
+  } as const,
+};
+
+/**
+ * Expected shape for a SearchResult object in JSON output
