+  requiredFields: ["prompt", "score", "matchedFields"] as const,
+  types: {
+    prompt: "object",
+    score: "number",
+    matchedFields: "array",
+  } as const,
+};
+
+/**
+ * Expected shape for error payloads
+ */
+const EXPECTED_ERROR_SCHEMA = {
+  notFound: { error: "not_found" },
+};
+
